import axios from "axios";

/* =========================
   AXIOS BASE INSTANCE
========================= */
export const API = axios.create({
  baseURL: "http://localhost:5000/api",
});

/* =========================
   Attach Token Automatically
========================= */
API.interceptors.request.use((req) => {
  const token = localStorage.getItem("token");
  if (token) {
    req.headers.Authorization = `Bearer ${token}`;
  }
  return req;
});

/* =========================
   Submit Bug (MUST send testUrl + payload)
========================= */
export const submitBug = (data) => {
  return API.post("/bugs/submit", {
    title: data.title,
    description: data.description,
    testUrl: data.testUrl,      // required for sandbox
    payload: data.payload,      // required for sandbox
    severity: data.severity || "low",
    steps: data.steps || "",
    attachments: data.attachments || [],
  });
};

/* =========================
   Run Sandbox (POST)
========================= */
export const runSandbox = (bugId) => {
  return API.post(`/company/sandbox/${bugId}`);
};

/* =========================
   Get Company Analytics
========================= */
export const getCompanyAnalytics = () => {
  return API.get("/company/analytics");
};

/* =========================
   Get Company Wallet
========================= */
export const getCompanyWallet = () => {
  return API.get("/company/wallet");
};
